#!/usr/bin/env python3
import base64, os

ROOT = "."
def w(p, d):
    f = os.path.join(ROOT, p)
    dd = os.path.dirname(f)
    if dd: os.makedirs(dd, exist_ok=True)
    with open(f, "wb") as file:
        file.write(base64.b64decode(d))
    print(f"  WROTE  {p}")

print("=== TuneAi Compose UI Decoder ===")
w('app/src/main/java/com/tuneai/app/ui/Theme.kt', "")
w('app/src/main/java/com/tuneai/app/ui/Composables.kt', "")
print("=== DONE: UI package decoded ===")
